import{_ as d,o as r,c as a,ag as e}from"./chunks/framework.CQYuu_FX.js";const c=JSON.parse('{"title":"シフト管理","description":"","frontmatter":{"title":"シフト管理"},"headers":[],"relativePath":"tenant/12-shift.md","filePath":"tenant/12-shift.md"}'),l={name:"tenant/12-shift.md"};function o(i,t,h,n,s,b){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="_12-シフト管理" tabindex="-1">12. シフト管理 <a class="header-anchor" href="#_12-シフト管理" aria-label="Permalink to &quot;12. シフト管理&quot;">​</a></h1><p>シフト管理では、スタッフの希望提出、週間シフト作成、公開前チェック、勤務確認、交代・欠勤申請、当日の不足確認、勤怠打刻、実績差分、店舗間ヘルプ、人件費の目安確認を行います。</p><p>POSLA の前提は <strong>1 人 1 アカウント</strong>です。device アカウントは KDS、レジ、ハンディなどの備品端末用であり、シフト割当、勤怠、人件費、スタッフ評価の対象には入りません。</p><h2 id="_12-1-画面構成" tabindex="-1">12-1. 画面構成 <a class="header-anchor" href="#_12-1-画面構成" aria-label="Permalink to &quot;12-1. 画面構成&quot;">​</a></h2><table tabindex="0"><thead><tr><th>画面</th><th>使う人</th><th>目的</th></tr></thead><tbody><tr><td>週間カレンダー</td><td>manager 以上</td><td>週単位でシフトを作成、公開前チェック、確定</td></tr><tr><td>マイシフト</td><td>staff / manager</td><td>自分のシフト確認、確認済み、交代依頼、欠勤連絡</td></tr><tr><td>希望提出</td><td>staff</td><td>勤務できる日、希望時間、勤務不可を提出</td></tr><tr><td>勤怠一覧</td><td>manager 以上</td><td>出勤、退勤、休憩、打刻修正</td></tr><tr><td>テンプレート</td><td>manager 以上</td><td>曜日・時間帯・必要人数・持ち場の基本形を登録</td></tr><tr><td>シフト設定</td><td>manager 以上</td><td>休憩、残業判定、GPS、時給、目標人件費率、持ち場を設定</td></tr><tr><td>集計サマリー</td><td>manager 以上</td><td>週次・月次の労働時間、実績人件費、人件費率、労務警告を確認</td></tr><tr><td>当日・ヘルプ</td><td>manager 以上</td><td>今日の未打刻、欠勤、時間帯不足、呼べる候補、店舗間ヘルプ、交代/欠勤申請を確認</td></tr></tbody></table><h2 id="_12-2-標準フロー" tabindex="-1">12-2. 標準フロー <a class="header-anchor" href="#_12-2-標準フロー" aria-label="Permalink to &quot;12-2. 標準フロー&quot;">​</a></h2><ol><li>スタッフが <strong>希望提出</strong> で勤務可否を出す</li><li>マネージャーが <strong>テンプレート</strong> または <strong>週間カレンダー</strong> でシフトを作る</li><li>必要な時間帯に持ち場を入れる</li><li>6 時間超、8 時間超の勤務は休憩時間を確認する</li><li>週間カレンダー上部の <strong>公開前チェック</strong> を確認する</li><li>人数不足、持ち場不足、休憩不足、希望未提出、予定人件費率、労務リスク、ヘルプ候補を見て修正する</li><li>問題がなければ <strong>確定する</strong> を押す</li><li>スタッフは <strong>マイシフト</strong> で自分の確定シフトを確認し、<strong>確認</strong> を押す</li><li>交代や欠勤が必要な場合、スタッフはマイシフトから <strong>交代依頼</strong> または <strong>欠勤連絡</strong> を送る</li><li>店長は <strong>当日・ヘルプ</strong> で未対応申請、未打刻、当日の時間帯不足を確認する</li></ol><p>外部メッセージ通知は POSLA の確定操作だけでは送られません。希望未提出者への連絡は、公開前チェックの <strong>リマインド文コピー</strong> を使い、店舗の通常連絡手段で送ってください。</p><h2 id="_12-3-持ち場" tabindex="-1">12-3. 持ち場 <a class="header-anchor" href="#_12-3-持ち場" aria-label="Permalink to &quot;12-3. 持ち場&quot;">​</a></h2><p>持ち場は、シフトで「何の仕事に入るか」を表す店舗別のマスタです。</p><p>初期値は以下です。</p><table tabindex="0"><thead><tr><th>code</th><th>表示名</th></tr></thead><tbody><tr><td><code>hall</code></td><td>ホール</td></tr><tr><td><code>kitchen</code></td><td>キッチン</td></tr></tbody></table><p>店舗に合わせて、シフト設定から追加できます。</p><p>例:</p><table tabindex="0"><thead><tr><th>code</th><th>表示名</th><th>用途</th></tr></thead><tbody><tr><td><code>drink</code></td><td>ドリンク</td><td>バー、ドリンク場</td></tr><tr><td><code>wash</code></td><td>洗い場</td><td>洗い場専任</td></tr><tr><td><code>cashier</code></td><td>レジ</td><td>レジ横担当</td></tr><tr><td><code>prep</code></td><td>仕込み</td><td>仕込み担当</td></tr></tbody></table><p>運用ルール:</p><ul><li><code>code</code> は英数字、<code>_</code>、<code>-</code> の 20 文字以内</li><li>表示名は店長・スタッフが画面で見る名前</li><li>非表示にした持ち場は新規選択に出なくなる</li><li>非表示にしても過去のシフト履歴は残る</li><li>公開前チェックの持ち場不足は、テンプレートに指定した持ち場を基準に判定する</li></ul><h2 id="_12-4-公開前チェック" tabindex="-1">12-4. 公開前チェック <a class="header-anchor" href="#_12-4-公開前チェック" aria-label="Permalink to &quot;12-4. 公開前チェック&quot;">​</a></h2><p>週間カレンダーを開くと、カレンダー上部に公開前チェックが表示されます。これは AI ではなく、POSLA 内の実データを集計して判定します。</p><h3 id="表示される内容" tabindex="-1">表示される内容 <a class="header-anchor" href="#表示される内容" aria-label="Permalink to &quot;表示される内容&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>時間帯ごとの人数不足</td><td>テンプレート必要人数、過去 8 週間の同曜日・同時間帯売上、対象日の予約人数から必要人数を出し、予定人数と比較</td></tr><tr><td>持ち場不足</td><td>テンプレートで持ち場が指定されている時間帯について、予定シフトの持ち場数と比較</td></tr><tr><td>休憩未設定/不足</td><td>6 時間超は 45 分、8 時間超は 60 分を目安に不足を警告</td></tr><tr><td>希望未提出スタッフ</td><td>対象週で希望提出がない、または一部の日だけ未提出のスタッフを一覧表示</td></tr><tr><td>リマインド文</td><td>希望未提出者向けの連絡文をまとめてコピー</td></tr><tr><td>予約・売上予測</td><td>時間帯別に、過去売上平均、平均注文数、予約組数、予約人数を表示</td></tr><tr><td>予定人件費率</td><td>予定シフトの人件費目安を、過去売上平均と比較。店舗設定の目標人件費率を超えると警告</td></tr><tr><td>労務リスク</td><td>予定上の週 40 時間超、1 日 8 時間超、6 日以上連続勤務を表示</td></tr><tr><td>未確認シフト</td><td>確定済みだが、スタッフがマイシフトでまだ確認していないシフトを表示</td></tr><tr><td>実績差分</td><td>予定と勤怠打刻を比較し、遅刻、早退、残業、打刻なしを表示</td></tr><tr><td>ヘルプ候補</td><td>人数不足の時間帯について、他店舗スタッフの候補を表示</td></tr></tbody></table><h3 id="赤・黄・情報の考え方" tabindex="-1">赤・黄・情報の考え方 <a class="header-anchor" href="#赤・黄・情報の考え方" aria-label="Permalink to &quot;赤・黄・情報の考え方&quot;">​</a></h3><table tabindex="0"><thead><tr><th>表示</th><th>意味</th><th>推奨対応</th></tr></thead><tbody><tr><td>赤</td><td>人数不足が大きい、休憩 0 分の長時間勤務、予定人件費率が大きく超過など、公開前に確認すべき状態</td><td>シフト追加、休憩入力、時間変更、売上見込みの確認</td></tr><tr><td>黄</td><td>人数不足 1 人、持ち場不足、希望未提出、勤怠差分、予定人件費率の軽い超過など</td><td>店長判断で修正またはそのまま確定</td></tr><tr><td>情報</td><td>未確認シフト、軽微な労務リスクなど、見ておくとよい内容</td><td>必要に応じて確認</td></tr></tbody></table><p>公開前チェックに警告が残っていても、最終判断として <strong>確定する</strong> ことはできます。POSLA は現場判断を止めず、見落としを減らすために警告を表示します。</p><h3 id="予定人件費率の見方" tabindex="-1">予定人件費率の見方 <a class="header-anchor" href="#予定人件費率の見方" aria-label="Permalink to &quot;予定人件費率の見方&quot;">​</a></h3><p>予定人件費率は次の式です。</p><p><code>予定人件費 ÷ 過去売上平均 × 100</code></p><p>予定人件費は、スタッフ個別時給があれば個別時給、なければ店舗デフォルト時給で計算します。どちらも未設定のスタッフがいる場合、その人の人件費は計算できません。</p><p>予約人数は必要人数の判定に使いますが、予約を売上金額へ自動換算して人件費率の分母には入れません。宴会、コース単価、貸切などは店舗側の判断で見てください。</p><h2 id="_12-5-必要人数提案の考え方" tabindex="-1">12-5. 必要人数提案の考え方 <a class="header-anchor" href="#_12-5-必要人数提案の考え方" aria-label="Permalink to &quot;12-5. 必要人数提案の考え方&quot;">​</a></h2><p>必要人数は以下のうち一番大きい値を採用します。</p><table tabindex="0"><thead><tr><th>入力データ</th><th>判定</th></tr></thead><tbody><tr><td>シフトテンプレート</td><td>曜日・時間帯ごとに登録した必要人数</td></tr><tr><td>過去売上</td><td>過去 8 週間の同曜日・同時間帯の平均売上と平均注文数</td></tr><tr><td>予約</td><td>対象日の予約組数と予約人数</td></tr></tbody></table><p>目安ルール:</p><ul><li>平均注文数が多い時間帯は必要人数を上げる</li><li>売上が大きい時間帯は必要人数を上げる</li><li>予約人数が多い時間帯は必要人数を上げる</li><li>テンプレートの必要人数がある場合は、それを最低ラインとして扱う</li></ul><p>これは給与計算や労務判断の最終決定ではありません。予約の内容、宴会、研修、新人比率、料理提供の難易度など、POSLA に入っていない事情は店長が調整してください。</p><h2 id="_12-6-マイシフト確認" tabindex="-1">12-6. マイシフト確認 <a class="header-anchor" href="#_12-6-マイシフト確認" aria-label="Permalink to &quot;12-6. マイシフト確認&quot;">​</a></h2><p>スタッフは、確定した自分のシフトを <strong>マイシフト</strong> で確認します。</p><p>操作:</p><ol><li>スタッフが管理画面にログイン</li><li><strong>シフト管理</strong> → <strong>マイシフト</strong> を開く</li><li>自分のシフトだけを見る</li><li>確定シフトに問題がなければ <strong>確認</strong> を押す</li><li>ステータスが <strong>確認済</strong> になる</li></ol><p>店長側では、公開前チェックに未確認件数と未確認者が表示されます。外部メッセージの既読確認ではなく、POSLA のマイシフト上で確認されたかを表します。</p><h2 id="_12-7-交代依頼と欠勤連絡" tabindex="-1">12-7. 交代依頼と欠勤連絡 <a class="header-anchor" href="#_12-7-交代依頼と欠勤連絡" aria-label="Permalink to &quot;12-7. 交代依頼と欠勤連絡&quot;">​</a></h2><p>スタッフは、未来日または当日の確定済みシフトについて、マイシフトから交代依頼または欠勤連絡を送れます。</p><h3 id="交代依頼" tabindex="-1">交代依頼 <a class="header-anchor" href="#交代依頼" aria-label="Permalink to &quot;交代依頼&quot;">​</a></h3><ol><li>スタッフが <strong>マイシフト</strong> を開く</li><li>対象シフトの <strong>交代依頼</strong> を押す</li><li>候補スタッフが表示される</li><li>候補を選ぶ、または候補を指定せずに送る</li><li>店長へのメモを入力して送信</li></ol><p>候補は以下を見て出ます。</p><ul><li>同じ店舗の staff アカウント</li><li>対象シフトと同じ時間帯に別シフトが重なっていない</li><li>希望提出が <code>希望</code> または <code>出勤可</code> なら優先</li><li>希望が <code>不可</code> の人は除外</li><li>対象時間と希望時間が重ならない人は除外</li><li>過去 90 日のシフト履歴から、同じ持ち場経験があれば優先</li></ul><h3 id="欠勤連絡" tabindex="-1">欠勤連絡 <a class="header-anchor" href="#欠勤連絡" aria-label="Permalink to &quot;欠勤連絡&quot;">​</a></h3><ol><li>スタッフが <strong>マイシフト</strong> を開く</li><li>対象シフトの <strong>欠勤連絡</strong> を押す</li><li>理由や店長へのメモを入力する</li><li>送信する</li></ol><p>欠勤連絡を送っただけでは、シフトは自動削除されません。店長が当日・ヘルプ画面で承認または却下します。</p><h3 id="店長の承認" tabindex="-1">店長の承認 <a class="header-anchor" href="#店長の承認" aria-label="Permalink to &quot;店長の承認&quot;">​</a></h3><p>店長は <strong>当日・ヘルプ</strong> の <strong>交代・欠勤申請</strong> で対応します。</p><table tabindex="0"><thead><tr><th>操作</th><th>結果</th></tr></thead><tbody><tr><td>交代スタッフを選んで承認</td><td>元のシフト担当者が交代スタッフに差し替わる</td></tr><tr><td>交代なしで承認</td><td>欠勤だけ承認される。シフトの不足は当日不足に残る</td></tr><tr><td>却下</td><td>申請は却下され、元のシフトは変わらない</td></tr><tr><td>キャンセル</td><td>申請を取り消す</td></tr></tbody></table><p>一度対応済みになった申請は、未対応一覧には戻りません。誤って承認した場合は、週間カレンダーでシフトを直接修正してください。</p><h2 id="_12-8-当日・ヘルプ" tabindex="-1">12-8. 当日・ヘルプ <a class="header-anchor" href="#_12-8-当日・ヘルプ" aria-label="Permalink to &quot;12-8. 当日・ヘルプ&quot;">​</a></h2><p><strong>当日・ヘルプ</strong> は、店長が「今日まず何を見るべきか」を確認する画面です。</p><p>表示される内容:</p><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>開始済み未打刻</td><td>予定開始から 15 分超過しても出勤打刻がないスタッフ</td></tr><tr><td>未対応の交代/欠勤</td><td>まだ承認・却下されていない申請</td></tr><tr><td>承認済み欠勤</td><td>欠勤だけ承認され、交代スタッフが入っていないシフト</td></tr><tr><td>時間帯不足</td><td>テンプレート必要人数に対して、当日の予定人数が不足している時間帯</td></tr><tr><td>今日呼べる候補</td><td>今日シフトが入っていない同店舗スタッフ</td></tr><tr><td>店舗間ヘルプ</td><td>他店舗への送信要請、他店舗からの受信要請</td></tr></tbody></table><p>承認済み欠勤は、未打刻とは別に表示されます。欠勤が承認済みなのに未打刻として残ると現場が迷うためです。</p><h2 id="_12-9-ヘルプ募集" tabindex="-1">12-9. ヘルプ募集 <a class="header-anchor" href="#_12-9-ヘルプ募集" aria-label="Permalink to &quot;12-9. ヘルプ募集&quot;">​</a></h2><p>人手が足りない時間帯は、公開前チェックと当日・ヘルプ画面の両方で候補を確認できます。</p><h3 id="公開前チェックで見る" tabindex="-1">公開前チェックで見る <a class="header-anchor" href="#公開前チェックで見る" aria-label="Permalink to &quot;公開前チェックで見る&quot;">​</a></h3><p>人数不足がある時間帯に、他店舗スタッフ候補が表示されます。</p><p>候補は以下を見て並びます。</p><ul><li>同じテナント内の他店舗スタッフである</li><li>対象日・対象時間帯に既存シフトが重なっていない</li><li>希望提出が <code>希望</code> または <code>出勤可</code> なら優先</li><li>希望未提出でも、重複シフトがなければ「要確認」の候補として表示</li><li>過去 90 日のシフト履歴から、指定持ち場の経験があれば優先</li></ul><h3 id="当日・ヘルプ画面から送る" tabindex="-1">当日・ヘルプ画面から送る <a class="header-anchor" href="#当日・ヘルプ画面から送る" aria-label="Permalink to &quot;当日・ヘルプ画面から送る&quot;">​</a></h3><ol><li><strong>当日・ヘルプ</strong> タブを開く</li><li><strong>新規要請</strong> を押す</li><li>送信先店舗、日付、時間、必要人数、持ち場を入力する</li><li>入力欄の下に候補スタッフが表示される</li><li>候補を見て、送信先店舗が妥当か確認する</li><li><strong>送信</strong> を押す</li></ol><p>承認するのは要請先店舗のマネージャーです。承認時に派遣スタッフを選択すると、要請元店舗のシフトにヘルプとして登録されます。</p><h2 id="_12-10-テンプレートの作り方" tabindex="-1">12-10. テンプレートの作り方 <a class="header-anchor" href="#_12-10-テンプレートの作り方" aria-label="Permalink to &quot;12-10. テンプレートの作り方&quot;">​</a></h2><p>テンプレートは、公開前チェックの最低必要人数にも使われます。</p><p>例:</p><table tabindex="0"><thead><tr><th>名前</th><th>曜日</th><th>時間</th><th>必要人数</th><th>持ち場</th></tr></thead><tbody><tr><td>平日ランチ ホール</td><td>月〜金</td><td>10:00-14:00</td><td>2</td><td>ホール</td></tr><tr><td>平日ランチ キッチン</td><td>月〜金</td><td>10:00-14:00</td><td>2</td><td>キッチン</td></tr><tr><td>週末ディナー</td><td>土日</td><td>17:00-22:00</td><td>5</td><td>指定なし</td></tr></tbody></table><p>持ち場不足まで正確に見たい場合は、ホール用、キッチン用、ドリンク用などに分けてテンプレートを作ってください。持ち場を「指定なし」にすると、人数不足は確認できますが、持ち場別の不足までは判定しません。</p><h2 id="_12-11-勤怠打刻と実績差分" tabindex="-1">12-11. 勤怠打刻と実績差分 <a class="header-anchor" href="#_12-11-勤怠打刻と実績差分" aria-label="Permalink to &quot;12-11. 勤怠打刻と実績差分&quot;">​</a></h2><p>スタッフは出勤時に <strong>出勤</strong>、退勤時に <strong>退勤</strong> を打刻します。GPS 打刻を有効にしている店舗では、店舗付近での打刻が必要です。</p><p>実績差分は公開前チェックと集計サマリーで確認します。</p><table tabindex="0"><thead><tr><th>差分</th><th>表示条件</th></tr></thead><tbody><tr><td>打刻なし</td><td>確定シフトが過去日で、対応する勤怠打刻がない</td></tr><tr><td>遅刻</td><td>予定開始より 5 分超遅れて出勤</td></tr><tr><td>早退</td><td>予定終了より 5 分超早く退勤</td></tr><tr><td>残業</td><td>予定労働時間より 15 分超長く勤務</td></tr></tbody></table><p>打刻漏れや誤りがある場合は、<strong>勤怠一覧</strong> から該当行を修正します。修正理由は監査ログに残るため、理由欄は空にしないでください。</p><h2 id="_12-12-人件費確認" tabindex="-1">12-12. 人件費確認 <a class="header-anchor" href="#_12-12-人件費確認" aria-label="Permalink to &quot;12-12. 人件費確認&quot;">​</a></h2><p>人件費は以下を使って目安計算します。</p><ul><li>店舗デフォルト時給</li><li>スタッフ個別時給</li><li>シフト時間</li><li>休憩時間</li><li>深夜時間帯の割増目安</li><li>勤怠実績</li><li>実際の売上</li></ul><p>週間カレンダーの公開前チェックは <strong>予定人件費率</strong>、集計サマリーは <strong>実績人件費率</strong> を見ます。</p><table tabindex="0"><thead><tr><th>場所</th><th>使うデータ</th><th>目的</th></tr></thead><tbody><tr><td>公開前チェック</td><td>予定シフト、時給、過去売上平均</td><td>公開前に組みすぎを見つける</td></tr><tr><td>集計サマリー</td><td>勤怠実績、時給、期間内の実売上</td><td>実際の人件費と売上のバランスを見る</td></tr></tbody></table><p>給与計算の最終確定は、店舗または本部の給与運用に従ってください。POSLA の表示は現場確認用の目安です。</p><h2 id="_12-13-シフト設定" tabindex="-1">12-13. シフト設定 <a class="header-anchor" href="#_12-13-シフト設定" aria-label="Permalink to &quot;12-13. シフト設定&quot;">​</a></h2><p>シフト設定では以下を設定します。</p><table tabindex="0"><thead><tr><th>項目</th><th>内容</th></tr></thead><tbody><tr><td>希望提出締切日</td><td>希望提出の目安日</td></tr><tr><td>デフォルト休憩</td><td>新規シフト作成時の休憩目安</td></tr><tr><td>残業判定分</td><td>勤怠差分の残業判定に使う目安</td></tr><tr><td>早出許容分</td><td>早めに出勤打刻した場合の許容目安</td></tr><tr><td>自動退勤時間</td><td>打刻忘れ対策の自動退勤閾値</td></tr><tr><td>GPS 設定</td><td>店舗緯度、経度、許容半径、GPS 必須</td></tr><tr><td>店舗デフォルト時給</td><td>人件費目安の計算に使う</td></tr><tr><td>目標人件費率</td><td>公開前チェックと集計サマリーの警告基準</td></tr><tr><td>持ち場</td><td>店舗ごとの役割名を登録・非表示</td></tr></tbody></table><h2 id="_12-14-困ったとき" tabindex="-1">12-14. 困ったとき <a class="header-anchor" href="#_12-14-困ったとき" aria-label="Permalink to &quot;12-14. 困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>確認すること</th></tr></thead><tbody><tr><td>公開前チェックで人数不足が出る</td><td>テンプレート必要人数、予約人数、売上予測、実際の割当人数を確認</td></tr><tr><td>持ち場不足が出ない</td><td>テンプレートの持ち場が指定されているか確認</td></tr><tr><td>希望未提出が多い</td><td>リマインド文をコピーして通常連絡手段で送る</td></tr><tr><td>スタッフが確認済みにならない</td><td>スタッフがマイシフトで <strong>確認</strong> を押しているか確認</td></tr><tr><td>交代候補が出ない</td><td>同時間帯シフト重複、希望不可、希望時間外、同店舗スタッフ登録を確認</td></tr><tr><td>欠勤承認後に不足が残る</td><td>交代スタッフなしで承認した状態。必要なら当日・ヘルプから呼べる候補、または店舗間ヘルプを使う</td></tr><tr><td>ヘルプ候補が出ない</td><td>他店舗スタッフ、希望提出、同時間帯シフト重複、店舗所属を確認</td></tr><tr><td>打刻できない</td><td>ログイン中のアカウント、位置情報許可、店舗付近かを確認</td></tr><tr><td>人件費が想定と違う</td><td>時給設定、休憩、深夜時間、勤怠修正、期間内売上の有無を確認</td></tr></tbody></table>',88)])])}const g=d(l,[["render",o]]);export{c as __pageData,g as default};
